VALUES
  ('bookkeeper-moex-01092', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '屏東公司 X5 年報導期間結束日應收帳款總額$970,000，並設定應收帳款總額的 6%為其期末備抵壞帳餘 額。X6 年中，實際沖銷壞帳$38,800。經評估，於 X6 年期末加提$34,500 為其應收帳款之備抵壞帳。試 問X6年底備抵壞帳之餘額為:', '["$53,900", "$58,200", "$38,800", "$19,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01093', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '高雄公司於X6年10月1日購入一部價值$1,500,000的機器，估計使用年限4年，預計總產量10,000,000 單位，估計殘值為$100,000，假設X6年共產出600,000單位。以直線法折舊，則X6年底之折舊費用為:', '["$90,000", "$58,333", "$60,000", "$87,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01094', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年初以$500,000購入乙公司30%股份分類為採用權益法之投資。乙公司X1年之本期淨利為 $100,000，其他綜合損益為損失$200,000，X1 年並發放現金股利$10,000。若甲公司對乙公司投資之原始 成本等於股權淨值，甲公司X1年該投資帳面金額之變動數為（不考慮所得稅影響）：', '["減少$33,000", "減少$30,000", "增加$27,000", "增加$30,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01095', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '基隆公司購置機器一部，定價$500,000。廠商提供現金折扣$55,000，支付運費$30,000，運送中因超速被 罰款$16,000。運抵廠房後另付安裝費$35,000，則該機器應有之帳面成本為：', '["$510,000", "$526,000", "$475,000", "$491,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01096', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '宜蘭公司於X6年3月1日發行面額$2,000,000，利率8%，市場利率為10%之3年期公司債，發行價格為 $1,898,485。利息於每年2月28日及8月31日各付息一次。宜蘭公司按有效利率法攤銷公司債溢折價。 試問該公司於X6年12月31日調整應認列之利息費用為多少？', '["$63,780", "$80,000", "$94,924", "$14,924"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01097', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '假設其他條件都不變的情況之下，下列何者為公司買回庫藏股時不會發生之情形？', '["權益總額減少", "現金總額減少", "公司流通在外股數減少", "每股盈餘變少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01098', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '雲林公司X6年1月1日流通在外普通股200,000股，4月1日辦理現金減資，減少流通在外普通股20,000股， 5月1日買回普通股20,000股，8月1日對外發行普通股20,000股，並於12月1日出售庫藏股15,000股， 試計算雲林公司X6年度普通股加權平均流通在外股數：', '["181,250", "194,583", "176,250", "165,417"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01099', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何者之會計處理可能影響保留盈餘之金額？①買入庫藏股  ②出售庫藏股  ③買入備供出售金融資產', '["出售備供出售金融資產", "僅", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01100', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年初之應收帳款總額$1,800，備抵壞帳為貸餘$600，X1年底之應收帳款總額$2,100，備抵壞帳 為貸餘$400，X1年之壞帳損失為$100。在該公司以間接法編製之X1年現金流量表中，關於應收帳款項 目對淨利之調整數共計：', '["減少$500", "減少$400", "減少$300", "減少$200"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01101', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年底以$200,000購入耐用年限10年之熔爐一座，熔爐裝有價值$4,000，按法規每4年即須汰 換並重置之防火內襯。甲公司對熔爐與防火內襯均以直線法提列折舊，估計無殘值，後續衡量採成本模 式。X3年底法規更改為每2年即須汰換並重置防火內襯，故該公司以$5,000汰換重置防火內襯。若此重 置支出符合資本支出之條件，則此重置對該公司X3年淨利之影響為（不考慮所得稅）：', '["無影響", "減少淨利$2,000", "減少淨利$5,000", "減少淨利$7,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
